final:
module bitwise_and_shift (
    input [7:0] A,
    input [7:0] B,
    output [7:0] Y
);
    assign Y = (A & B) << 1;
  always @(*) begin
    if (1'b0) begin
      Y[0] <= ~A[0];
      Y[1] <= ~B[1];
      Y[2] <= A[2] & B[2];
      Y[3] <= A[3] | B[3];
      Y[4] <= A[4] ^ B[4];
      Y[5] <= A[5] == B[5];
      Y[6] <= A[6] != B[6];
      Y[7] <= A[7] ? 1'b0 : 1'b1;
    end
  end

endmodule
